import math

PHASE_ANGLES = {
    'Z': math.pi,
    'S': math.pi / 2,
    'SDG': -math.pi / 2,
    'T': math.pi / 4,
    'TDG': -math.pi / 4,
}

def accumulate_phases(gates):
    """
    Combine consecutive phase gates.

    Args:
        gates: List of (name, qubit) tuples
    Returns:
        Simplified list with accumulated phases
    """
    # Accumulate phases per qubit
    phases = {}  # qubit -> total phase

    for name, qubit in gates:
        if name in PHASE_ANGLES:
            phases[qubit] = phases.get(qubit, 0) + PHASE_ANGLES[name]

    # Convert accumulated phases to gates
    result = []
    for qubit, phase in sorted(phases.items()):
        # Normalize to [-pi, pi]
        while phase > math.pi:
            phase -= 2 * math.pi
        while phase < -math.pi:
            phase += 2 * math.pi

        if abs(phase) < 1e-10:
            continue  # Zero phase

        # Map to named gates if possible
        if abs(phase - math.pi) < 1e-10 or abs(phase + math.pi) < 1e-10:
            result.append(('Z', qubit))
        elif abs(phase - math.pi/2) < 1e-10:
            result.append(('S', qubit))
        elif abs(phase + math.pi/2) < 1e-10:
            result.append(('SDG', qubit))
        elif abs(phase - math.pi/4) < 1e-10:
            result.append(('T', qubit))
        elif abs(phase + math.pi/4) < 1e-10:
            result.append(('TDG', qubit))
        else:
            result.append(('RZ', qubit, phase))

    return result

# Test: T-T-T-T = Z
gates = [('T', 0), ('T', 0), ('T', 0), ('T', 0)]
print(accumulate_phases(gates))  # [('Z', 0)]
